INSERT INTO articles (id, title, slug, summary, content, cover_image, category_id, topic_id, parent_id, author, status, article_type, view_count, published_at, created_at, updated_at, collected_at, lang, sentiment, tickers, key_points, source, source_url, subcategory, audit_status) VALUES (165, 'Green Transition Reshapes Copper Derivatives Pricing: Deep Dive into New Linkages Between Futures and Options Markets | YayaNews', 'green-transition-reshapes-copper-derivatives-pricing-deep-dive-into-new-linkages', 'A deep analysis of how copper, as a critical metal in the global energy transition, is exhibiting new characteristics in its futures pricing and options volatility surface. The article reveals how a ''green premium'' is being priced in, how markets are preparing for upside ''black swans'', and how macro and industry logic is reshaping the risk pricing framework for derivatives.', '<h2>Introduction: The ''New Copper Age'' in the Green Wave</h2>
