INSERT INTO articles (id, title, slug, summary, content, cover_image, category_id, topic_id, parent_id, author, status, article_type, view_count, published_at, created_at, updated_at, collected_at, lang, sentiment, tickers, key_points, source, source_url, subcategory, audit_status) VALUES (182, 'Ethereum Cancun Upgrade Activated: Layer2 Transaction Costs Plunge, Reshaping Arbitrum, Optimism Ecosystems and Token Economics', 'ethereum-cancun-upgrade-activated-layer2-transaction-costs-plunge-reshaping-arbi', 'In-depth analysis of how the Ethereum Cancun upgrade, via EIP-4844, reduces transaction fees and boosts performance for Layer2 networks like Arbitrum and Optimism, with long-term structural impacts on DeFi, NFT ecosystems, and token value capture models.', '<h2><a href="https://yayanews.cryptooptiontool.com/search?q=%E4%BB%A5%E5%A4%AA%E5%9D%8A">Ethereum</a> Cancun Upgrade: A Paradigm Shift for the Layer2 Ecosystem</h2>
INSERT INTO articles (id, title, slug, summary, content, cover_image, category_id, topic_id, parent_id, author, status, article_type, view_count, published_at, created_at, updated_at, collected_at, lang, sentiment, tickers, key_points, source, source_url, subcategory, audit_status) VALUES (183, 'Crypto Today: South Korea Tightens Crypto Exchange Reserve Rules', 'crypto-today-south-korea-tightens-crypto-exchange-reserve-rules', 'Today in crypto, Bitcoin ETFs rebound, South Korea mandates 5-minute asset checks for crypto exchanges, and SEC crypto safe harbor heads to White House review.', '<p>Today in crypto, Bitcoin ETFs rebound, South Korea mandates 5-minute asset checks for crypto exchanges, and SEC crypto safe harbor heads to White House review.</p><p>Crypto Today: South Korea Tightens Crypto Exchange Reserve Rules</p><p>Ecosystem</p><p>SOL</p><p>$84.64</p><p>6.22%</p><p>ETH</p><p>$2,246</p><p>6.89%</p><p>BTC</p><p>$71,536</p><p>4.62%</p><p>XMR</p><p>$341.46</p><p>3.14%</p><p>DOGE</p><p>$0.09455</p><p>4.20%</p><p>BNB</p><p>$612.57</p><p>2.46%</p><p>BCH</p><p>$446.07</p><p>3.17%</p><p>XLM</p><p>$0.1627</p><p>4.80%</p><p>LINK</p><p>$9.20</p><p>5.43%</p><p>ADA</p><p>$0.2592</p><p>6.45%</p><p>TRX</p><p>$0.3164</p><p>0.56%</p><p>XRP</p><p>$1.38</p><p>5.50%</p><p>HYPE</p><p>$39.27</p><p>7.35%</p><p>USD</p><p>Written by</p><p>Cointelegraph</p><p>,</p><p>Staff Writer</p><p>Reviewed by</p><p>Bryan O''Shea</p><p>,</p><p>Staff Editor</p><p>Here’s what happened in crypto today</p><p>14 hours ago</p><p>Need to know what happened in crypto today? Here is the latest news on daily trends and events impacting Bitcoin price, blockchain, DeFi, NFTs, Web3 and crypto regulation.</p><p>Listen</p><p>0:00</p><p>News</p><p>Cointelegraph in your social feed</p><p>Follow our</p><p>Subscribe on</p><p>Today in crypto, inflows into US spot Bitcoin exchange-traded funds (ETFs) rebounded sharply this week, suggesting that institutional selling is finally reversing course. Elsewhere, South Korea ordered all crypto exchanges to verify their actual asset holdings every five minutes,  and US Securities and Exchange Commission (SEC) Chair Paul Atkins said the crypto market safe harbor proposal is now at the White House Office of Information and Regulatory Affairs for review.</p><p>Bitcoin ETF inflows rebound sharply, led by BlackRock</p><p>US-listed spot Bitcoin ETFs saw</p><p>strong investor demand on April 6</p><p>, recording $471 million in net inflows — the largest single-day total since late February, according to SoSoValue. The surge marks a notable shift after weeks of selling activity, suggesting institutional appetite for Bitcoin exposure is picking up again.</p><p>The bulk of inflows was concentrated in a few major funds, led by BlackRock’s iShares Bitcoin Trust and Fidelity’s Wise Origin Bitcoin Fund, with ARK 21Shares’ ETF also contributing significantly.</p><p>The renewed momentum follows a broader turnaround that began in March, when Bitcoin ETFs returned to net positive flows after experiencing outflows earlier in the year. Total assets under management have climbed back above $90 billion, indicating that capital is re-entering the sector as market conditions stabilize.</p><p>Despite the positive inflow data,</p><p>market sentiment remains sensitive</p><p>to macroeconomic forces. Analysts note that upcoming inflation data and broader economic signals could still influence whether this recovery in ETF demand continues or proves short-lived.</p><p>Source:</p><p>Arkham</p><p>South Korea orders crypto exchanges to verify holdings every five minutes</p><p>South Korea has ordered all crypto exchanges to</p><p>reconcile their internal ledgers with actual asset holdings</p><p>every five minutes after an inspection uncovered weaknesses in internal controls.</p><p>The directive was</p><p>announced</p><p>on Monday by the Financial Services Commission (FSC) after a meeting with top crypto exchanges and the Digital Asset Exchange Alliance (DAXA), during which they discussed the findings of an emergency</p><p>inspection triggered by the Bithumb</p><p>payout incident.</p><p>The inspection found that three of the country’s five major exchanges were reconciling balances only once every 24 hours, limiting their ability to respond quickly to discrepancies. Systems designed to halt trading during major mismatches were also found to be insufficient, raising concerns about how exchanges would handle large-scale errors.</p><p>In February,</p><p>Bithumb mistakenly distributed</p><p>620,000 Bitcoin (</p><p>BTC</p><p>) to 249 users during a promotional event. The exchange later announced that it</p><p>recovered 99.7% of the funds</p><p>the same day. The remaining 0.3%, 1,788 BTC that had already been sold, was covered using company reserves.</p><p>Under the new measures, exchanges must implement automated ledger-to-wallet reconciliation systems operating on a five-minute cycle. They will also be required to introduce defined criteria for triggering automatic transaction halts in the event of significant discrepancies.</p><p>Top Korean crypto exchanges. Source:</p><p>CoinGecko</p><p>Crypto market safe harbor lands at White House for review</p><p>US Securities and Exchange Commission Chair Paul Atkins has revealed that a key</p><p>crypto market safe harbor proposal</p><p>has landed at the White House for review.</p><p>Speaking at the Digital Assets and Emerging Technology Policy Summit on Monday, Atkins</p><p>said</p><p>the Regulation Crypto Assets proposal — outlined by the SEC in mid-March — has now been submitted to the Office of Information and Regulatory Affairs.</p><p>&quot;We will have reg crypto that we will be proposing here shortly. It''s in fact at OIRA right now, which is the next step before being published,&quot; he said.</p><p>Source:</p><p>Paul Atkins</p><p>Regulation Crypto Assets covers three main ideas: a startup exemption, a fundraising exemption and an</p><p>investment contract safe harbor</p><p>for issuers.</p><p>If the proposal does end up becoming official rules as part of the SEC’s oversight,  it could drive more crypto innovation in the US while providing further</p><p>regulatory clarity</p><p>for the industry.</p><p>Atkins emphasized that the SEC wants to &quot;hear from the marketplace&quot; to make the whole package &quot;workable.&quot; He did not go into many specifics but said there were a few things the SEC is &quot;building into it&quot; alongside measures such as crypto safe harbors and exemptive relief.</p><p>Cointelegraph is committed to independent, transparent journalism. This news article is produced in accordance with Cointelegraph’s Editorial Policy and aims to provide accurate and timely information. Readers are encouraged to verify information independently. Read our Editorial Policy</p><p>https://cointelegraph.com/editorial-policy</p><p>#</p><p>Cryptocurrencies</p><p>#</p><p>South Korea</p><p>#</p><p>Cryptocurrency Exchange</p><p>#</p><p>Donald Trump</p><p>#</p><p>Bitcoin ETF</p><p>#</p><p>Industry</p>', 'https://images.cointelegraph.com/cdn-cgi/image/f=auto,onerror=redirect,w=1200/https://s3.cointelegraph.com/uploads/2026-02/019c6669-7e16-7fb4-9f62-9215e7a70fb0.jpg', 2, NULL, NULL, 'YayaNews', 'published', 'standard', 0, '2026-04-07 11:48:08', '2026-04-08 18:56:19', '2026-04-08 18:56:19', '2026-04-08 18:56:19', 'en', 'neutral', 'BTC,ETH', '', 'CoinTelegraph', 'https://cointelegraph.com/news/what-happened-in-crypto-today?utm_source=rss_feed&utm_medium=rss&utm_campaign=rss_partner_inbound', '', 'approved') ON CONFLICT (id) DO NOTHING;
